import os
import shutil

def is_empty_directory(path):
    """
    Checks if a directory is empty.

    Args:
    path (str): The path to the directory to check.

    Returns:
    bool: True if the directory is empty, False otherwise.
    """
    try:
        return len(os.listdir(path)) == 0
    except Exception as e:
        print(f"Error checking directory {path}: {e}")
        return False


def delete_empty_directory(path):
    """
    Recursively deletes an empty directory.

    Args:
    path (str): The path to the directory to delete.
    """
    try:
        if os.path.isdir(path):
            if is_empty_directory(path):
                shutil.rmtree(path)
                print(f"Deleted empty directory: {path}")
            else:
                print(f"Skipping non-empty directory: {path}")
        else:
            print(f"Skipping non-directory path: {path}")
    except Exception as e:
        print(f"Error deleting directory {path}: {e}")


def main():
    root_dir = input("Enter the root directory to sanitize: ")
    if not os.path.isdir(root_dir):
        print(f"Error: {root_dir} is not a valid directory")
        return

    try:
        delete_empty_directory(root_dir)
